import redis  # noqa: E402, F401

redisConn = redis.Redis(host='localhost', port=6379)


def main():

    while True:
        operation = input('Enter operation: ')

        if 'eval' in operation and '\'' not in operation:
            redisKey = eval(input('Enter key name: '))

            redisValue = eval(
                input("Enter value that's to be stored into the redis key"))
